             (SELECT p.image FROM products p WHERE p.category = c.id 
              AND p.image IS NOT NULL AND p.image NOT LIKE '%placehold%' 
              LIMIT 1) as img1,
             (SELECT p.image FROM products p WHERE p.category = c.id 
              AND p.image IS NOT NULL AND p.image NOT LIKE '%placehold%' 
              OFFSET 1 LIMIT 1) as img2
             FROM categories c ORDER BY c.name`
});
console.log(result.output);
